// ===== TopWorstSellers.js =====
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';
import { segmentOptions, highlightOptions, seasonOptions, locationOptions } from './Icons/optionbarOptions';

// Import icons (categoryIconMap, seasonIconMap, highlight icons, location icons)...

export default function TopWorstSellers() {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [businessCity, setBusinessCity] = useState('');
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    const [filters, setFilters] = useState({
        segments:   new Set(segmentOptions.map(o => o.id)),
        highlights: new Set(highlightOptions.map(o => o.id)),
        seasons:    new Set(seasonOptions.map(o => o.id)),
        locations:  new Set(locationOptions.map(o => o.id)),
    });

    // Fetch business city
    useEffect(() => {
        axios.get('/api/business-info', { withCredentials:true })
            .then(res => setBusinessCity(res.data.city || ''))
            .catch(console.error);
    }, []);

    // Fetch sales
    useEffect(() => {
        setLoading(true);
        axios.get('/api/sales', { withCredentials:true })
            .then(res => {
                const mapped = res.data.map(i => ({
                    id:           i.id_menu_item,
                    name:         i.item_name,
                    count:        i.total_sold ?? i.sold_count,
                    categoryId:   i.id_category,
                    category:     i.category,
                    high_margin:  i.is_high_margin === 1,
                    trending:     i.is_trending === 1,
                    eco_friendly: i.eco_friendly === 'Yes' || i.eco_friendly === 1,
                    season:       i.season || 'Unknown',
                    prodCity:     i.stad,
                    prodCountry:  i.land
                }));
                setItems(mapped);
            })
            .catch(err => { console.error(err); setError('Kon verkoopcijfers niet laden'); })
            .finally(() => setLoading(false));
    }, []);

    if(loading) return <p>Loading…</p>;
    if(error)   return <p className="error">{error}</p>;

    // Sort
    const sorted = [...items].sort((a,b) =>
        sortOrder==='top' ? b.count - a.count : a.count - b.count
    );

    // Filtered by search + filters
    const visible = sorted.filter(item => {
        // search
        if(!item.name.toLowerCase().includes(searchTerm.toLowerCase())) return false;
        // segment filter
        if(!filters.segments.has(item.categoryId)) return false;

        // highlight filter: must match any selected highlight if any toggled
        const highlightSelected = Array.from(filters.highlights);
        if(highlightSelected.length) {
            const checks = [];
            if(filters.highlights.has(highlightOptions.find(o=>o.label==='High Margin').id)) checks.push(item.high_margin);
            if(filters.highlights.has(highlightOptions.find(o=>o.label==='Trending').id))    checks.push(item.trending);
            if(filters.highlights.has(highlightOptions.find(o=>o.label==='Eco Friendly').id)){ checks.push(item.eco_friendly); }
            if(checks.length && !checks.some(v=>v)) return false;
        }

        // season filter
        const seasonOpt = seasonOptions.find(o => o.label===item.season);
        if(seasonOpt && !filters.seasons.has(seasonOpt.id)) return false;

        // location filter
        // determine item location category
        const locKey = item.prodCity===businessCity ? 'Locally Produced'
            : (item.prodCountry==='Belgium' ? 'Made in Belgium' : 'Sourced Globally');
        const locOpt = locationOptions.find(o=>o.label===locKey);
        if(locOpt && !filters.locations.has(locOpt.id)) return false;

        return true;
    });

    return (
        <div className="top-worst-container">
            {/* Debug */}
            <div className="debug-segments">
                <strong>Selected Segments:</strong> {Array.from(filters.segments).join(', ')}
            </div>

            <div className="centre-content">
                {/* header/search */}
                <div className="list-header">{
                    /* ... */
                }</div>
                <ul className="items-list">
                    {visible.map((item,idx)=>(
                        <li key={item.id} className="item">
                            {/* ... render item ... */}
                        </li>
                    ))}
                </ul>
            </div>

            <Optionbar filters={filters} onChange={setFilters} />
        </div>
    );
}
